import java.util.HashMap;
import sailpoint.object.Link;
import sailpoint.object.Identity;
import sailpoint.object.Application;
import sailpoint.object.Identity;
import sailpoint.tools.Util;
import sailpoint.api.IdentityService;
import org.apache.log4j.Logger; 
import org.apache.log4j.Level;
import org.apache.commons.logging.LogFactory;

Logger olcLog = Logger.getLogger("rule.toyota.OrgLdapCorrelation");
olcLog.trace("TOC-001: Executing  rule.toyota.OrgLdapCorrelation");

String uniqueUid = "";
String name = "";
String employeeNumber = "";

Map returnMap = new HashMap();

// Get attributes for matching
try {

   String idenName = account.getIdentity();

  olcLog.trace(" account.getIdentity method in try ....."+idenName);
  uniqueUid = account.getStringAttribute( "uniqueUid" );             
  employeeNumber = account.getStringAttribute( "employeeNumber" );
  olcLog.trace("TOC-002: uniqueUid value : "+  uniqueUid);

  if( Util.isNotNullOrEmpty(uniqueUid) ){
    name = uniqueUid.substring(0, uniqueUid.indexOf("@"));
    if( Util.isNotNullOrEmpty(name) ){
      returnMap.put("identityName", name);
       olcLog.trace("TOC-002: name value : "+  name);

    }
  }
  else if( Util.isNotNullOrEmpty(employeeNumber) ){

    IdentityService idService = new IdentityService(context);
    Application appObj = context.getObjectByName(Application.class,"WorkerDB");            
    Identity iden = null;

    String idenName = account.getIdentity();

    log.error(" account.getIdentity method ....."+idenName);
    if(idenName != null){
      iden = context.getObjectByName(Identity.class,idenName);
    }
    if(iden != null){
      List links = idService.getLinks(iden,appObj);
      if( Util.nullSafeSize(links) ){
        String workdayId = links.get(0).getAttribute("WORKDAYID");    
        if( Util.nullSafeEq(employeeNumber,workdayId )){
          returnMap.put("identity", iden);
        }
      }

    }
  }
}  
} catch ( Exception ex ) {
    olcLog.trace("TOC-003: ERROR:: retreiving attribute(s) " + ex );
}

 olcLog.trace( "TOC-004: Correlation Map for "+account.getStringAttribute( "uniqueUid" )+" is--- " + returnMap.toString() );
 olcLog.trace( "TOC-005: Exiting Rule Rule-OrgLdapCorrelation for "+account.getStringAttribute( "employeeNumber" ) );

return returnMap;
